mapper.insert:
INSERT INTO NAS_FOLDER (
    FOLDER_ID
    , USER_CODE
    , PARENT_FOLDER_ID
    , FOLDER_NAME
) VALUES (
    uuid_in(md5(random()::text || now()::text)::cstring)
    , #{userCode}
    , #{folderId}
    , #{folderName}
)

mapper.update:
UPDATE NAS_FOLDER
   SET FOLDER_NAME = #{changeName}
 WHERE USER_CODE = #{userCode}
   AND FOLDER_ID = #{folderId}
   AND PARENT_FOLDER_ID = #{parentFolderId}

mapper.select:
SELECT FILE_ID
  FROM NAS_FILE
 WHERE USER_CODE = #{userCode}
   AND FOLDER_ID = #{folderId}

mapper.update:
UPDATE NAS_FOLDER
SET DELETE_YN = 'Y'
  , DELETED_AT = NOW()
WHERE DELETE_YN = 'N'
  AND USER_CODE = #{userCode}
  AND PARENT_FOLDER_ID = #{parentFolderId}
  AND FOLDER_ID = #{folderId}

mapper.delete:
UPDATE NAS_FILE
   SET DELETE_YN = 'Y'
     , DELETED_AT = NOW()
 WHERE DELETE_YN = 'N'
   AND USER_CODE = #{userCode}
   AND FILE_ID = #{fileId}
   AND FOLDER_ID = #{folderId}
